    ...searchMarkets.map((x) => normalizeCandidate(x, "search_markets"))
  ].filter((x) => isMacroCandidate(x));

  const uniqueCandidates = dedupeCandidates(rawCandidates);

  const rankedCandidates = pickTopSemanticCandidates({
